import json

# Get business data
business_data = var_functions.query_db:18

print('Loaded ' + str(len(business_data)) + ' businesses')

# Simple analysis
wifi_count = 0
state_counts = {}

for business in business_data:
    # Check WiFi
    attrs = business.get('attributes')
    has_wifi = False

    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        if wifi_val:
            wifi_str = str(wifi_val).lower()
            if 'no' not in wifi_str:
                has_wifi = True

    # Get state
    state = None
    desc = business.get('description', '')
    if ', ' in desc:
        parts = desc.rsplit(', ', 1)
        if len(parts) == 2:
            state_part = parts[1].strip()
            if len(state_part) >= 2:
                possible_state = state_part[:2]
                if possible_state.isalpha():
                    state = possible_state

    if has_wifi and state:
        wifi_count += 1
        if state in state_counts:
            state_counts[state] = state_counts[state] + 1
        else:
            state_counts[state] = 1

print('WiFi businesses: ' + str(wifi_count))
print('State counts: ' + str(state_counts))

# Get reviews for these businesses
wifi_biz_ids = []
for business in business_data:
    attrs = business.get('attributes')
    has_wifi = False

    if isinstance(attrs, dict):
        wifi_val = attrs.get('WiFi')
        if wifi_val:
            wifi_str = str(wifi_val).lower()
            if 'no' not in wifi_str:
                has_wifi = True

    if has_wifi:
        biz_id = business.get('business_id')
        if biz_id:
            wifi_biz_ids.append(biz_id.replace('businessid_', ''))

result = {
    'wifi_count': wifi_count,
    'state_counts': state_counts,
    'wifi_biz_ids': wifi_biz_ids,
    'top_state': None
}

if state_counts:
    top_state = max(state_counts, key=state_counts.get)
    result['top_state'] = top_state
    result['top_state_count'] = state_counts[top_state]

print('__RESULT__:')
print(json.dumps(result))

